        ax.axhline(y=0, color=theme.colors.get("grid", "#cccccc"), linewidth=0.5)

        n_violations = int(np.sum(violations))
        expected = n_obs * (1 - cl)
        ratio = n_violations / expected if expected > 0 else 0

